def print_uop_tree(uop, indent=0):
    prefix = '  ' * indent
    if hasattr(uop, 'op'):
        print(f'{prefix}{uop.op} shape={uop.shape} dtype={uop.dtype}')
        if uop.op.name == 'REDUCE':
            print(f'{prefix}  arg={uop.arg}')
        for s in uop.src:
            print_uop_tree(s, indent + 1)
    else:
        print(f'{prefix}{uop}')

print_uop_tree(out.uop)
